#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=2e3+5;
int f[MAXN][MAXN],n,m,t;
int main(void){
    n=read(),m=read();
    for(int i=1;i<=m;++i)f[0][i]=inf;
	for(int i=1,c,l;i<=n;++i)
    {
        c=read(),l=read();
		for(int j=m;j>=0;--j)
        {
			f[i][j]=min(f[i-1][j],f[i-1][max(j-l,0)]+c);
		}
	}
    if(f[n][m]!=inf)write(f[n][m]);
    else puts("no solution");
	return false;
}
